// 路線別 運行実績・定時性ダッシュボード
// 蒼洋電鉄株式会社 — 輸送計画部 運行品質グループ / 内部運行コンソール
//
// Server Component shell. All interactive parts (function props / state) live behind
// "use client" boundaries in sibling files; this file passes only plain data + nodes.

import { Container, PageHeader, Badge, Separator } from "@gunjo/ui";
import { SectionCard } from "./SectionCard";
import { KpiStrip } from "./KpiStrip";
