        <SectionCard
          title="月次・四半期レポート"
          description="運行実績レポート(PDF)・遅延データ(CSV)・路線別内訳(XLSX) をダウンロード。"
        >
          <ReportDownloads />
        </SectionCard>
      </Container>
    </div>
  );
}

"use client";

// 混雑率 (congestion) — each line's peak-section congestion vs the 150% 要対策ライン.
//
// @gunjo/ui `LimitMonitor`: value vs a NAMED limit (soft 150% + hard 180%), with
// near/over/critical states derived from the limit and a line drawn on the bar — a
// far better fit than Meter here because the threshold is a real regulatory figure in
// the value's own units, not a fraction of an arbitrary max. `formatValue` (function
// prop) → client. Sorted worst-first.

import { LimitMonitor } from "@gunjo/ui";
import { lines, CONGESTION_LIMIT, CONGESTION_HARD_LIMIT } from "./data";
import { congestion } from "./formatters";

export function CongestionPanel() {
  const ordered = [...lines].sort((a, b) => b.peakCongestion - a.peakCongestion);
  return (
    <div className="flex flex-col gap-4">
      {ordered.map((l) => (
        <LimitMonitor
          key={l.id}
          label={`${l.name}（${l.peakSection}）`}
          value={l.peakCongestion}
          limit={CONGESTION_LIMIT}
          hardLimit={CONGESTION_HARD_LIMIT}
          warnWithin={15}
          max={200}
          formatValue={congestion}
          labels={{
            ok: "目安内",
            near: "目安間近",
            over: "要対策",
            critical: "上限超過",
          }}
        />
      ))}
    </div>
  );
}

