import { formatNumber, formatPercent } from "@gunjo/ui";

/** "94.6%" from a percent-value (already scaled, not a ratio). */
export const pct = (v: number): string =>
  formatPercent(v, { asPercentValue: true, maximumFractionDigits: 1 });

/** "+0.4pt" / "−0.4pt" — signed point delta. */
