  const items: ActionItem[] = [];

  for (const l of lines) {
    if (l.punctuality < PUNCTUALITY_TARGET) {
      const gap = (PUNCTUALITY_TARGET - l.punctuality).toFixed(1);
      items.push({
        id: `${l.id}-punctuality`,
        severity: l.punctuality < 91 ? "critical" : "warning",
        kind: "定時率未達",
        title: `${l.name}：定時率 ${l.punctuality.toFixed(1)}%（目標−${gap}pt）`,
        detail: `平均遅延 ${l.avgDelayMin.toFixed(1)}分・遅延 ${l.delays.toLocaleString(
          "ja-JP"
        )}件。ダイヤ余裕時分の見直しを検討。`,
        meta: `${l.origin}→${l.destination}`,
        actions: (
          <Button variant="outline" size="sm">
            詳細
          </Button>
        ),
      });
    }
    if (l.peakCongestion > CONGESTION_LIMIT) {
      items.push({
        id: `${l.id}-congestion`,
        severity: l.peakCongestion >= 180 ? "critical" : "warning",
        kind: "混雑率超過",
        title: `${l.name}：最混雑率 ${l.peakCongestion}%（要対策ライン150%超）`,
        detail: `最混雑区間 ${l.peakSection}。増発・両数増の検討対象。`,
        meta: `${l.trainsPerDay}本/日`,
        actions: (
          <Button variant="outline" size="sm">
            増発検討
          </Button>
        ),
      });
    }
    if (l.incidents >= 10) {
      items.push({
        id: `${l.id}-incidents`,
        severity: "warning",
        kind: "輸送障害多発",
        title: `${l.name}：輸送障害 ${l.incidents}件（当月）`,
        detail: "設備・車両故障の内訳を確認し、予防保全計画に反映。",
        meta: `運休 ${l.suspensions}回`,
      });
    }
  }
  return items;
}

export function IssueQueue() {
  return (
    <ActionQueue
      items={buildItems()}
      sortBySeverity
      emptyLabel="対応が必要な路線はありません"
    />
  );
}

"use client";

// 全社KPIサマリ (KPI strip).
//
// THE CRUX: @gunjo/ui's `Statistic` exposes `trend` (drives the arrow) and `tone`
// (drives the colour) as TWO SEPARATE props, with `tone` defaulting from `trend`
// (up→positive/green, down→negative/red). There is NO `goodWhen` / direction prop.
// For "good when LOW" metrics (遅延件数・平均遅延・輸送障害・混雑率) the default would
// paint a worsening (rising) number GREEN — wrong. So we compute tone ourselves from
// the sign × the metric's good-direction, while keeping `trend` honest to the raw
// movement (arrow still points the way the number actually moved).

import { StatGroup, type StatisticProps } from "@gunjo/ui";
import { company } from "./data";
import { pct, pt, count, countSigned, minutes, minutesSigned, congestion } from "./formatters";

type GoodWhen = "high" | "low";

/**
 * Map a signed change + good-direction onto Statistic's (trend, tone).
 * - `trend` = which way the arrow points = the raw direction of the number.
 * - `tone`  = green/red/grey by whether that movement is actually GOOD.
 */
function directionProps(
  delta: number,
  goodWhen: GoodWhen
): Pick<StatisticProps, "trend" | "tone"> {
  if (delta === 0) return { trend: "flat", tone: "neutral" };
  const rising = delta > 0;
  const isGood = goodWhen === "high" ? rising : !rising;
  return {
    trend: rising ? "up" : "down",
    tone: isGood ? "positive" : "negative",
  };
}

export function KpiStrip() {
  const items: StatisticProps[] = [
    {
      label: "定時運行率（全社平均）",
      value: pct(company.punctuality),
      change: `${pt(company.punctualityTargetPt)}（目標比）`,
      hint: "目標 95.0%",
      ...directionProps(company.punctualityTargetPt, "high"),
    },
    {
      label: "遅延件数（5分以上・当月）",
      value: count(company.delays),
      change: `${countSigned(company.delaysYoY)}（前年比）`,
      hint: "低いほど良い",
      ...directionProps(company.delaysYoY, "low"),
    },
    {
      label: "平均遅延時分",
      value: minutes(company.avgDelayMin),
      change: `${minutesSigned(company.avgDelayYoY)}（前年比）`,
      hint: "低いほど良い",
      ...directionProps(company.avgDelayYoY, "low"),
    },
    {
      label: "輸送障害件数（当月）",
      value: count(company.incidents),
      change: `${countSigned(company.incidentsYoY)}（前年比）`,
      hint: "低いほど良い",
      ...directionProps(company.incidentsYoY, "low"),
    },
    {
      label: "最混雑率（全社最大区間）",
      value: congestion(company.peakCongestion),
      change: `${pt(company.peakCongestionYoY)}（前年比）`,
      hint: "150%超で要対策",
      ...directionProps(company.peakCongestionYoY, "low"),
    },
  ];

  return <StatGroup items={items} cols={{ base: 1, sm: 2, md: 3, lg: 5 }} />;
}

"use client";

// 路線別の実績 (per-line performance table).
//
// @gunjo/ui `DataTable` (TanStack ColumnDef) → built-in sorting / filter / pagination.
// Cells compose: RouteHeader (hand-rolled A→B), Delta (inverted `tones` for good-low
// metrics), Meter inline (混雑率), Badge (worst flag). The "good direction" colour for
// the per-line deltas is handled by `Delta.tones` per sign — unlike `Statistic`, `Delta`
// DOES take per-sign tones, so 遅延件数 +58 reads red without manual sign math.

import * as React from "react";
import { DataTable, Delta, Meter, Badge, type ColumnDef } from "@gunjo/ui";
import { lines, type LineRow, PUNCTUALITY_TARGET, CONGESTION_LIMIT } from "./data";
import { RouteHeader } from "./RouteHeader";
import { pct, count, minutes, congestion } from "./formatters";

// "up is bad" tone map for delay-style deltas (rising = worse = red).
const WORSE_WHEN_UP = { positive: "destructive", negative: "success", zero: "muted" } as const;
// punctuality pt delta: rising = better = green (Delta's default), but be explicit.
const BETTER_WHEN_UP = { positive: "success", negative: "destructive", zero: "muted" } as const;

const headerRight = (label: string) => (
  <div className="text-right">{label}</div>
);

const columns: ColumnDef<LineRow>[] = [
  {
    accessorKey: "name",
    header: "路線（起点→終点）",
    enableSorting: true,
    cell: ({ row }) => {
      const l = row.original;
      return (
        <RouteHeader
          code={l.code}
          name={l.name}
          color={l.color}
          origin={l.origin}
          destination={l.destination}
          km={l.km}
        />
      );
    },
  },
  {
    accessorKey: "punctuality",
    header: () => headerRight("定時率"),
    enableSorting: true,
    cell: ({ row }) => {
      const l = row.original;
      const below = l.punctuality < PUNCTUALITY_TARGET;
      return (
        <div className="flex flex-col items-end gap-0.5">
          <span
            className={
              "text-sm font-semibold tabular-nums " +
              (below ? "text-destructive" : "text-foreground")
            }
          >
            {pct(l.punctuality)}
          </span>
          <Delta
            value={l.punctualityDelta}
            format={(v) => `${v > 0 ? "+" : v < 0 ? "−" : ""}${Math.abs(v).toFixed(1)}pt`}
            tones={BETTER_WHEN_UP}
            labels={{ positive: "改善", negative: "悪化", zero: "横ばい" }}
            className="text-xs"
          />
        </div>
      );
    },
  },
  {
    accessorKey: "delays",
    header: () => headerRight("遅延件数"),
    enableSorting: true,
    cell: ({ row }) => {
      const l = row.original;
      return (
        <div className="flex flex-col items-end gap-0.5">
          <span className="text-sm tabular-nums text-foreground">{count(l.delays)}</span>
          <Delta
            value={l.delaysDelta}
            format={(v) => `${v > 0 ? "+" : v < 0 ? "−" : ""}${Math.abs(v)}件`}
            tones={WORSE_WHEN_UP}
            labels={{ positive: "増加", negative: "減少", zero: "横ばい" }}
            className="text-xs"
          />
        </div>
      );
    },
  },
  {
    accessorKey: "avgDelayMin",
    header: () => headerRight("平均遅延"),
    enableSorting: true,
    cell: ({ row }) => (
      <div className="text-right text-sm tabular-nums text-foreground">
        {minutes(row.original.avgDelayMin)}
      </div>
    ),
  },
  {
    accessorKey: "incidents",
    header: () => headerRight("輸送障害"),
    enableSorting: true,
    cell: ({ row }) => {
      const n = row.original.incidents;
      return (
        <div className="text-right text-sm tabular-nums">
          <span className={n >= 10 ? "font-semibold text-destructive" : "text-foreground"}>
            {count(n)}
          </span>
        </div>
      );
    },
  },
  {
    accessorKey: "peakCongestion",
    header: () => headerRight("最混雑率"),
    enableSorting: true,
    cell: ({ row }) => {
      const l = row.original;
      return (
        <div className="flex w-40 flex-col items-end gap-0.5">
          <Meter
            value={l.peakCongestion}
            max={200}
            target={CONGESTION_LIMIT}
            size="inline"
            label={`${l.name} 混雑率`}
            formatValue={congestion}
          />
          <span className="truncate text-[11px] text-muted-foreground">{l.peakSection}</span>
        </div>
      );
    },
  },
  {
    id: "status",
    header: "判定",
    enableSorting: false,
    cell: ({ row }) => {
      const l = row.original;
      const flags: React.ReactNode[] = [];
      if (l.punctuality < PUNCTUALITY_TARGET) {
        flags.push(
          <Badge key="p" variant="destructive">
            定時率未達
          </Badge>
        );
      }
      if (l.peakCongestion > CONGESTION_LIMIT) {
        flags.push(
          <Badge key="c" variant="warning">
            混雑率超過
          </Badge>
        );
      }
      if (l.incidents >= 10) {
        flags.push(
          <Badge key="i" variant="warning">
            障害多発
          </Badge>
        );
      }
      if (flags.length === 0) {
        flags.push(
          <Badge key="ok" variant="success">
            良好
          </Badge>
        );
      }
      return <div className="flex flex-wrap gap-1">{flags}</div>;
    },
  },
];

export function LineTable() {
  return (
    <DataTable
      columns={columns}
      data={lines}
      pageSize={10}
      filter={{ columnId: "name", placeholder: "路線名で絞り込み" }}
      labels={{
        noResults: "該当する路線がありません",
        rowsPerPage: "表示件数",
        previous: "前へ",
        next: "次へ",
        sortAscending: "昇順に並べ替え",
        sortDescending: "降順に並べ替え",
      }}
    />
  );
}

"use client";

// 路線別 定時率ランキング / ワースト (best/worst line ranking).
//
// @gunjo/ui `Leaderboard`. Pre-ordered (caller owns order; rank = array index).
// `deltaTones` lets a "delay-rising = bad" chip read red. Two boards: worst定時率
// (needs attention) and worst遅延件数. Bars normalised against a sensible max so the
// fill is comparable. `formatValue` (function prop) → client component.

import { Leaderboard, type LeaderboardItem } from "@gunjo/ui";
import { lines, PUNCTUALITY_TARGET } from "./data";
import { pct } from "./formatters";

// punctuality delta: rising = better → green when positive (Delta default, explicit here).
const PUNCTUALITY_DELTA_TONES = { positive: "success", negative: "destructive" } as const;
// delay count: rising = worse → red when positive.
const DELAY_DELTA_TONES = { positive: "destructive", negative: "success" } as const;

export function PunctualityWorst() {
  // worst-first: lowest 定時率 at the top (needs attention).
  const items: LeaderboardItem[] = [...lines]
    .sort((a, b) => a.punctuality - b.punctuality)
    .map((l) => ({
      id: l.id,
      label: l.name,
      sublabel: `${l.origin}→${l.destination}`,
      value: l.punctuality,
      valueLabel: pct(l.punctuality),
      // normalise the bar against the 90–100 band so small gaps are visible.
      fraction: Math.max(0, (l.punctuality - 88) / (100 - 88)),
      delta: l.punctualityDelta,
      deltaLabel: `${l.punctualityDelta > 0 ? "+" : l.punctualityDelta < 0 ? "−" : ""}${Math.abs(
        l.punctualityDelta
      ).toFixed(1)}pt`,
      tone: l.punctuality < PUNCTUALITY_TARGET ? "destructive" : "success",
    }));

  return (
    <Leaderboard
      items={items}
      label="定時率ワースト（要注意路線）"
      deltaTones={PUNCTUALITY_DELTA_TONES}
      highlightTop={3}
    />
  );
}

export function DelayWorst() {
  const max = Math.max(...lines.map((l) => l.delays));
  const items: LeaderboardItem[] = [...lines]
    .sort((a, b) => b.delays - a.delays)
    .map((l) => ({
      id: l.id,
      label: l.name,
      sublabel: `平均遅延 ${l.avgDelayMin.toFixed(1)}分`,
      value: l.delays,
      valueLabel: `${l.delays.toLocaleString("ja-JP")}件`,
      delta: l.delaysDelta,
      deltaLabel: `${l.delaysDelta > 0 ? "+" : l.delaysDelta < 0 ? "−" : ""}${Math.abs(
        l.delaysDelta
      )}件`,
      tone: l.delays >= max * 0.6 ? "warning" : "muted",
    }));

  return (
    <Leaderboard
      items={items}
      label="遅延件数ワースト"
      max={max}
      deltaTones={DELAY_DELTA_TONES}
      highlightTop={3}
    />
  );
}

"use client";

// 月次レポートのダウンロード (report downloads).
//
// @gunjo/ui `SectionList` (the docs' pick for grouped document lists) wraps each group
// with a heading band + per-group meta; inside each section the rows are `NavRow`s
// (icon + label + value + trailing control) — there is no dedicated "document download
// row" component, so the row is composed from NavRow + a download Button. NavRow's
// `value` carries 種別/サイズ/更新日; the trailing Button is the download affordance.
// `onSelect` is intentionally omitted (the Button, not the whole row, downloads).

import { SectionList, NavRow, Button, Badge, type SectionListSection } from "@gunjo/ui";
import { IconFileTypePdf, IconFileTypeCsv, IconFileSpreadsheet, IconDownload } from "@tabler/icons-react";
import { reportGroups, type ReportFile } from "./data";

function kindIcon(kind: ReportFile["kind"]) {
  if (kind === "PDF") return <IconFileTypePdf className="h-5 w-5 text-destructive" />;
  if (kind === "CSV") return <IconFileTypeCsv className="h-5 w-5 text-success-strong" />;
  return <IconFileSpreadsheet className="h-5 w-5 text-info" />;
}

export function ReportDownloads() {
  const sections: SectionListSection[] = reportGroups.map((g) => ({
    key: g.key,
    title: g.title,
    sublabel: g.sublabel,
    meta: <Badge variant="secondary">{g.files.length}件</Badge>,
    content: (
      <div className="flex flex-col">
        {g.files.map((f) => (
          <NavRow
            key={f.id}
            icon={kindIcon(f.kind)}
            label={f.name}
            description={`${f.kind}・${f.size}`}
            value={<span className="text-xs text-muted-foreground">更新 {f.updated}</span>}
            trailing={
              <Button variant="outline" size="sm" aria-label={`${f.name}（${f.kind}）をダウンロード`}>
                <IconDownload className="h-4 w-4" />
                <span>DL</span>
              </Button>
            }
          />
        ))}
      </div>
    ),
  }));

  return <SectionList sections={sections} label="運行実績レポートのダウンロード" />;
}

"use client";

// 路線の起点→終点ヘッダー (A→B origin→destination).
//
// HAND-ROLLED. @gunjo/ui has NO OriginDestination / RouteHeader primitive.
// `RouteStops` is a vertical numbered itinerary (delivery/transfer step list), not a
// compact inline A→B header, and `LineChip` is only the line-identity pill. So the
// A→B composition (line chip + 起点 → 終点 + km) is page-specific glue built from
// LineChip + an arrow icon. This is the single most reusable missing primitive.

import { LineChip } from "@gunjo/ui";
import { IconArrowNarrowRight } from "@tabler/icons-react";

export interface RouteHeaderProps {
  code: string;
  name: string;
  color: string;
  origin: string;
  destination: string;
  km?: number;
  size?: "sm" | "default";
}

export function RouteHeader({
  code,
  name,
  color,
  origin,
  destination,
  km,
  size = "default",
}: RouteHeaderProps) {
  const small = size === "sm";
  return (
    <div className="flex min-w-0 items-center gap-2">
      <LineChip label={code} color={color} size={small ? "sm" : "default"} />
      <div className="flex min-w-0 flex-col">
        {!small && (
          <span className="truncate text-sm font-semibold text-foreground">{name}</span>
        )}
        <span
          className={
            small
              ? "flex items-center gap-1 text-xs text-foreground"
              : "flex items-center gap-1 text-xs text-muted-foreground"
          }
        >
          <span className="truncate">{origin}</span>
          <IconArrowNarrowRight className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
          <span className="truncate">{destination}</span>
          {km != null && (
            <span className="ml-1 shrink-0 tabular-nums text-muted-foreground">
              {km.toFixed(1)}km
            </span>
          )}
        </span>
      </div>
    </div>
  );
}

// RSC-safe section wrapper. No function props → stays a Server Component.
// Composed from @gunjo/ui Card primitives (Card / CardHeader / CardTitle /
// CardDescription / CardContent) so the docs site's dogfooding rule holds.
import * as React from "react";
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from "@gunjo/ui";

export function SectionCard({
  title,
  description,
  actions,
  children,
  className,
  contentClassName,
}: {
  title: React.ReactNode;
  description?: React.ReactNode;
  actions?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
  contentClassName?: string;
}) {
  return (
    <Card className={className}>
      <CardHeader className="flex flex-row items-start justify-between gap-3 space-y-0">
        <div className="flex min-w-0 flex-col gap-1">
          <CardTitle className="text-base">{title}</CardTitle>
          {description ? <CardDescription>{description}</CardDescription> : null}
        </div>
        {actions ? <div className="shrink-0">{actions}</div> : null}
      </CardHeader>
      <CardContent className={contentClassName}>{children}</CardContent>
    </Card>
  );
}

"use client";

// 推移 (trend) — 全社 定時率 over the quarter, with a target reference line.
//
// @gunjo/ui `LineChart`. `referenceValue` + `referenceLabel` draw the 目標95% line —
// exactly the "予算/目標線" the docs advertise. A SegmentedControl flips between
// 定時率 and 遅延件数 series so the same chart serves both trends. `formatValue`
// (function prop) → client. Two series shown for 定時率 (today vs 目標 baseline is the
// reference line; we keep a single real series and the reference for clarity).

import * as React from "react";
import { LineChart, SegmentedControl } from "@gunjo/ui";
import {
  companyPunctualityTrend,
  companyDelayTrend,
  PUNCTUALITY_TARGET,
} from "./data";

type Mode = "punctuality" | "delays";

export function TrendChart() {
  const [mode, setMode] = React.useState<Mode>("punctuality");

  const isP = mode === "punctuality";
  const source = isP ? companyPunctualityTrend : companyDelayTrend;

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center justify-between gap-2">
        <SegmentedControl
          aria-label="推移の指標切り替え"
          value={mode}
          onValueChange={(v) => setMode(v as Mode)}
          fullWidth={false}
          options={[
            { value: "punctuality", label: "定時率" },
            { value: "delays", label: "遅延件数" },
          ]}
        />
        <span className="text-xs text-muted-foreground">2026年度 第1四半期（週次）</span>
      </div>
      <LineChart
        series={[
          {
            label: isP ? "定時率" : "遅延件数",
            data: source,
            color: isP ? "info" : "destructive",
          },
        ]}
        variant="area"
        min={isP ? 92 : 0}
        max={isP ? 96 : undefined}
        referenceValue={isP ? PUNCTUALITY_TARGET : undefined}
        referenceLabel={isP ? "目標 95.0%" : undefined}
        showGrid
        showDots
        showLegend={false}
        formatValue={(v) =>
          isP ? `${v.toFixed(1)}%` : `${Math.round(v).toLocaleString("ja-JP")}件`
        }
      />
    </div>
  );
}
